// Package licenses exposes the aggregated third-party dependency notices,
// embedded so they are served offline (the frame runs air-gapped).
package licenses

import _ "embed"

// Notices is the merged THIRD_PARTY_NOTICES.txt (Go + bundled frontend deps),
// generated by `make notices`. Regenerate after changing dependencies.
//
//go:embed THIRD_PARTY_NOTICES.txt
var Notices string
